import{_ as e,c as o,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Início Rápido: Domine o Plannotator em 5 Minutos","description":"Aprenda a instalar e configurar o Plannotator. Complete a instalação do CLI em 5 minutos, configure o plugin para Claude Code ou OpenCode, e domine o fluxo de revisão de planos e código.","frontmatter":{"title":"Início Rápido: Domine o Plannotator em 5 Minutos","sidebarTitle":"Começar em 5 Minutos","subtitle":"Início Rápido: Domine o Plannotator em 5 Minutos","description":"Aprenda a instalar e configurar o Plannotator. Complete a instalação do CLI em 5 minutos, configure o plugin para Claude Code ou OpenCode, e domine o fluxo de revisão de planos e código.","tags":["Início Rápido","Introdução","Instalação","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"pt/backnotprop/plannotator/start/getting-started/index.md","filePath":"pt/backnotprop/plannotator/start/getting-started/index.md"}'),n={name:"pt/backnotprop/plannotator/start/getting-started/index.md"};function t(r,a,l,d,p,c){return i(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="inicio-rapido-domine-o-plannotator-em-5-minutos" tabindex="-1">Início Rápido: Domine o Plannotator em 5 Minutos <a class="header-anchor" href="#inicio-rapido-domine-o-plannotator-em-5-minutos" aria-label="Permalink to &quot;Início Rápido: Domine o Plannotator em 5 Minutos&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>✅ Entender as funcionalidades principais e casos de uso do Plannotator</li><li>✅ Completar a instalação do Plannotator em 5 minutos</li><li>✅ Configurar a integração com Claude Code ou OpenCode</li><li>✅ Realizar sua primeira revisão de plano e revisão de código</li></ul><h2 id="o-seu-dilema-atual" tabindex="-1">O Seu Dilema Atual <a class="header-anchor" href="#o-seu-dilema-atual" aria-label="Permalink to &quot;O Seu Dilema Atual&quot;">​</a></h2><p><strong>Plannotator</strong> é uma ferramenta de revisão interativa projetada para Claude Code e OpenCode, que ajuda a resolver os seguintes problemas:</p><p><strong>Problema 1</strong>: Planos de implementação gerados por IA são difíceis de ler no terminal — muito texto, estrutura confusa, revisão cansativa.</p><p><strong>Problema 2</strong>: Quando você quer dar feedback à IA, só pode descrever em texto &quot;delete o parágrafo 3&quot;, &quot;modifique esta função&quot; — alto custo de comunicação.</p><p><strong>Problema 3</strong>: Durante revisão de código, você precisa abrir múltiplos terminais ou IDEs, alternando constantemente, difícil manter o foco.</p><p><strong>Problema 4</strong>: Membros da equipe querem participar da revisão, mas não sabem como compartilhar o conteúdo do plano.</p><p><strong>O Plannotator pode ajudar você</strong>:</p><ul><li>Interface visual substitui leitura no terminal, estrutura clara</li><li>Selecione texto para adicionar anotações (excluir, substituir, comentar), feedback preciso</li><li>Revisão visual de Git diff, suporte a anotações por linha</li><li>Função de compartilhamento por URL, colaboração em equipe sem necessidade de backend</li></ul><h2 id="quando-usar-esta-abordagem" tabindex="-1">Quando Usar Esta Abordagem <a class="header-anchor" href="#quando-usar-esta-abordagem" aria-label="Permalink to &quot;Quando Usar Esta Abordagem&quot;">​</a></h2><p><strong>Cenários de uso</strong>:</p><ul><li>Usando Claude Code ou OpenCode para desenvolvimento assistido por IA</li><li>Precisa revisar planos de implementação gerados por IA</li><li>Precisa revisar alterações de código</li><li>Precisa compartilhar planos ou resultados de revisão de código com membros da equipe</li></ul><p><strong>Cenários não adequados</strong>:</p><ul><li>Código escrito manualmente (sem planos gerados por IA)</li><li>Já possui fluxo completo de revisão de código (como GitHub PR)</li><li>Não precisa de ferramenta de revisão visual</li></ul><h2 id="conceito-central" tabindex="-1">Conceito Central <a class="header-anchor" href="#conceito-central" aria-label="Permalink to &quot;Conceito Central&quot;">​</a></h2><h3 id="o-que-e-o-plannotator" tabindex="-1">O Que é o Plannotator <a class="header-anchor" href="#o-que-e-o-plannotator" aria-label="Permalink to &quot;O Que é o Plannotator&quot;">​</a></h3><p><strong>Plannotator</strong> é uma ferramenta de revisão interativa projetada para AI Coding Agents (Claude Code, OpenCode), oferecendo duas funcionalidades principais:</p><ol><li><strong>Revisão de Planos</strong>: Revisão visual de planos de implementação gerados por IA, com suporte a anotações, aprovação ou rejeição</li><li><strong>Revisão de Código</strong>: Revisão visual de Git diff, com suporte a anotações por linha e múltiplos modos de visualização</li></ol><h3 id="como-funciona" tabindex="-1">Como Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Como Funciona&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (gera plano)  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← Servidor HTTP local</span></span>
<span class="line"><span>│  (UI visual)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Navegador     │</span></span>
<span class="line"><span>│  (revisão)     │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>Fluxo principal</strong>:</p><ol><li>AI Agent completa o plano ou alterações de código</li><li>Plannotator inicia servidor HTTP local e abre o navegador</li><li>Usuário visualiza plano/código no navegador e adiciona anotações</li><li>Usuário aprova ou rejeita, Plannotator retorna a decisão ao AI Agent</li><li>AI Agent continua a implementação ou faz modificações baseado no feedback</li></ol><h3 id="seguranca" tabindex="-1">Segurança <a class="header-anchor" href="#seguranca" aria-label="Permalink to &quot;Segurança&quot;">​</a></h3><p><strong>Todos os dados são processados localmente</strong>, nada é enviado para a nuvem:</p><ul><li>Conteúdo do plano, diff de código e anotações são armazenados na sua máquina local</li><li>Servidor HTTP local usa porta aleatória (ou porta fixa)</li><li>Função de compartilhamento por URL implementada através de compressão de dados no hash da URL, sem necessidade de backend</li></ul><h2 id="🎒-preparativos-antes-de-comecar" tabindex="-1">🎒 Preparativos Antes de Começar <a class="header-anchor" href="#🎒-preparativos-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparativos Antes de Começar&quot;">​</a></h2><p><strong>Requisitos do sistema</strong>:</p><ul><li>Sistema operacional: macOS / Linux / Windows / WSL</li><li>Runtime: Bun (o script de instalação cuida disso automaticamente)</li><li>Ambiente de IA: Claude Code 2.1.7+ ou OpenCode</li></ul><p><strong>Escolha do método de instalação</strong>:</p><ul><li>Se usar Claude Code: precisa instalar CLI + plugin</li><li>Se usar OpenCode: precisa configurar o plugin</li><li>Se apenas fizer revisão de código: só precisa instalar o CLI</li></ul><h2 id="siga-minhas-operacoes" tabindex="-1">Siga Minhas Operações <a class="header-anchor" href="#siga-minhas-operacoes" aria-label="Permalink to &quot;Siga Minhas Operações&quot;">​</a></h2><h3 id="passo-1-instalar-o-plannotator-cli" tabindex="-1">Passo 1: Instalar o Plannotator CLI <a class="header-anchor" href="#passo-1-instalar-o-plannotator-cli" aria-label="Permalink to &quot;Passo 1: Instalar o Plannotator CLI&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>Você deve ver</strong>: O script de instalação baixará automaticamente o Plannotator CLI e o adicionará ao PATH do sistema, exibindo o número da versão (como &quot;plannotator v0.6.7 installed to ...&quot;).</p><div class="tip custom-block"><p class="custom-block-title">O que o script de instalação faz?</p><p>O script de instalação irá:</p><ol><li>Baixar a versão mais recente do Plannotator CLI</li><li>Adicionar ao PATH do sistema</li><li>Limpar versões antigas que possam existir</li><li>Instalar automaticamente o comando <code>/plannotator-review</code> (para revisão de código)</li></ol></div><h3 id="passo-2-configurar-claude-code-opcional" tabindex="-1">Passo 2: Configurar Claude Code (Opcional) <a class="header-anchor" href="#passo-2-configurar-claude-code-opcional" aria-label="Permalink to &quot;Passo 2: Configurar Claude Code (Opcional)&quot;">​</a></h3><p>Se você usa Claude Code, precisa instalar o plugin.</p><p><strong>Execute no Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>Importante</strong>: Após instalar o plugin, <strong>você deve reiniciar o Claude Code</strong> para que o hook entre em vigor.</p><p><strong>Você deve ver</strong>: Após a instalação bem-sucedida do plugin, <code>plannotator</code> aparecerá na lista de plugins do Claude Code.</p><div class="info custom-block"><p class="custom-block-title">Método de configuração manual (Opcional)</p><p>Se você não quiser usar o sistema de plugins, pode configurar o hook manualmente. Veja a seção <a href="./../installation-claude-code/">Instalação do Plugin Claude Code</a>.</p></div><h3 id="passo-3-configurar-opencode-opcional" tabindex="-1">Passo 3: Configurar OpenCode (Opcional) <a class="header-anchor" href="#passo-3-configurar-opencode-opcional" aria-label="Permalink to &quot;Passo 3: Configurar OpenCode (Opcional)&quot;">​</a></h3><p>Se você usa OpenCode, precisa editar o arquivo <code>opencode.json</code>.</p><p><strong>Edite <code>opencode.json</code></strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Reinicie o OpenCode</strong>.</p><p><strong>Você deve ver</strong>: Após reiniciar, o OpenCode carregará automaticamente o plugin, e a ferramenta <code>submit_plan</code> estará disponível.</p><h3 id="passo-4-primeira-revisao-de-plano-exemplo-com-claude-code" tabindex="-1">Passo 4: Primeira Revisão de Plano (Exemplo com Claude Code) <a class="header-anchor" href="#passo-4-primeira-revisao-de-plano-exemplo-com-claude-code" aria-label="Permalink to &quot;Passo 4: Primeira Revisão de Plano (Exemplo com Claude Code)&quot;">​</a></h3><p><strong>Condição de ativação</strong>: Faça o Claude Code gerar um plano de implementação e chamar <code>ExitPlanMode</code>.</p><p><strong>Exemplo de diálogo</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuário: Ajude-me a criar um plano de implementação para um módulo de autenticação de usuários</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Ok, aqui está o plano de implementação:</span></span>
<span class="line"><span>1. Criar modelo de usuário</span></span>
<span class="line"><span>2. Implementar API de registro</span></span>
<span class="line"><span>3. Implementar API de login</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(chama ExitPlanMode)</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ol><li>Navegador abre automaticamente a UI do Plannotator</li><li>Exibe o conteúdo do plano gerado pela IA</li><li>Você pode selecionar texto do plano e adicionar anotações (excluir, substituir, comentar)</li><li>Na parte inferior há botões &quot;Approve&quot; e &quot;Request Changes&quot;</li></ol><p><strong>Operações</strong>:</p><ol><li>Visualize o plano no navegador</li><li>Se o plano estiver ok, clique em <strong>Approve</strong> → IA continua a implementação</li><li>Se precisar de modificações, selecione o texto a modificar, clique em <strong>Delete</strong>, <strong>Replace</strong> ou <strong>Comment</strong> → clique em <strong>Request Changes</strong></li></ol><p><strong>Você deve ver</strong>: Após clicar, o navegador fechará automaticamente, e o Claude Code receberá sua decisão e continuará a execução.</p><h3 id="passo-5-primeira-revisao-de-codigo" tabindex="-1">Passo 5: Primeira Revisão de Código <a class="header-anchor" href="#passo-5-primeira-revisao-de-codigo" aria-label="Permalink to &quot;Passo 5: Primeira Revisão de Código&quot;">​</a></h3><p><strong>Execute no diretório do projeto</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ol><li>Navegador abre a página de revisão de código</li><li>Exibe o Git diff (por padrão, alterações não commitadas)</li><li>À esquerda está a árvore de arquivos, à direita o visualizador de diff</li><li>Clique nos números de linha para selecionar intervalo de código e adicionar anotações</li></ol><p><strong>Operações</strong>:</p><ol><li>Navegue pelas alterações de código no visualizador de diff</li><li>Clique nos números de linha para selecionar o código a revisar</li><li>No painel direito, adicione anotações (comment/suggestion/concern)</li><li>Clique em <strong>Send Feedback</strong> para enviar ao agent, ou clique em <strong>LGTM</strong> para aprovar</li></ol><p><strong>Você deve ver</strong>: Após clicar em Send Feedback, o navegador fechará, o terminal exibirá o conteúdo do feedback formatado, e o agent processará automaticamente.</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de Verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de Verificação ✅&quot;">​</a></h2><p>Após completar os passos acima, você deve ser capaz de:</p><ul><li>[ ] Script de instalação exibe &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] No Claude Code, acionar revisão de plano e navegador abre automaticamente a UI</li><li>[ ] Na UI, selecionar texto do plano e adicionar anotações</li><li>[ ] Clicar em Approve ou Request Changes e ver o navegador fechar</li><li>[ ] Executar <code>/plannotator-review</code> e ver a interface de revisão de código</li><li>[ ] Na revisão de código, adicionar anotações por linha e clicar em Send Feedback</li></ul><p><strong>Se algum passo falhar</strong>, consulte:</p><ul><li><a href="./../installation-claude-code/">Guia de Instalação Claude Code</a></li><li><a href="./../installation-opencode/">Guia de Instalação OpenCode</a></li><li><a href="./../../faq/common-problems/">Perguntas Frequentes</a></li></ul><h2 id="dicas-para-evitar-armadilhas" tabindex="-1">Dicas para Evitar Armadilhas <a class="header-anchor" href="#dicas-para-evitar-armadilhas" aria-label="Permalink to &quot;Dicas para Evitar Armadilhas&quot;">​</a></h2><p><strong>Erro comum 1</strong>: Após instalação, executar <code>plannotator</code> mostra &quot;command not found&quot;</p><p><strong>Causa</strong>: Variável de ambiente PATH não atualizada, ou precisa reiniciar o terminal.</p><p><strong>Solução</strong>:</p><ul><li>macOS/Linux: Execute <code>source ~/.zshrc</code> ou <code>source ~/.bashrc</code>, ou reinicie o terminal</li><li>Windows: Reinicie o PowerShell ou CMD</li></ul><p><strong>Erro comum 2</strong>: Após instalar plugin no Claude Code, revisão de plano não é acionada</p><p><strong>Causa</strong>: Claude Code não foi reiniciado, hook não entrou em vigor.</p><p><strong>Solução</strong>: Feche completamente o Claude Code (não apenas fechar a janela), depois reabra.</p><p><strong>Erro comum 3</strong>: Navegador não abre automaticamente</p><p><strong>Causa</strong>: Pode ser modo remoto (como devcontainer, SSH), ou porta ocupada.</p><p><strong>Solução</strong>:</p><ul><li>Verifique se a variável de ambiente <code>PLANNOTATOR_REMOTE=1</code> está definida</li><li>Veja a URL exibida no terminal e abra manualmente no navegador</li><li>Consulte <a href="./../../advanced/remote-mode/">Modo Remoto/Devcontainer</a></li></ul><p><strong>Erro comum 4</strong>: Revisão de código mostra &quot;No changes&quot;</p><p><strong>Causa</strong>: Não há alterações git não commitadas no momento.</p><p><strong>Solução</strong>:</p><ul><li>Execute <code>git status</code> primeiro para confirmar que há alterações</li><li>Ou execute <code>git add</code> para preparar alguns arquivos</li><li>Ou mude para outro tipo de diff (como last commit)</li></ul><h2 id="resumo-da-aula" tabindex="-1">Resumo da Aula <a class="header-anchor" href="#resumo-da-aula" aria-label="Permalink to &quot;Resumo da Aula&quot;">​</a></h2><p>Plannotator é uma ferramenta de revisão que roda localmente, melhorando a eficiência da revisão de planos e código através de uma UI visual:</p><p><strong>Funcionalidades principais</strong>:</p><ul><li><strong>Revisão de Planos</strong>: Revisão visual de planos gerados por IA, com suporte a anotações precisas</li><li><strong>Revisão de Código</strong>: Revisão visual de Git diff, com suporte a anotações por linha</li><li><strong>Compartilhamento por URL</strong>: Compartilhe conteúdo de revisão sem necessidade de backend</li><li><strong>Integração com terceiros</strong>: Salva automaticamente planos aprovados no Obsidian/Bear</li></ul><p><strong>Vantagens principais</strong>:</p><ul><li>Execução local, dados seguros</li><li>UI visual, maior eficiência</li><li>Feedback preciso, menor custo de comunicação</li><li>Colaboração em equipe, sem necessidade de sistema de contas</li></ul><h2 id="proximo-passo" tabindex="-1">Próximo Passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo Passo&quot;">​</a></h2><blockquote><p>Na próxima aula aprenderemos <strong><a href="./../installation-claude-code/">Instalação do Plugin Claude Code</a></strong>.</p><p>Você aprenderá:</p><ul><li>Passos detalhados de instalação do plugin Claude Code</li><li>Método de configuração manual do hook</li><li>Como verificar se a instalação foi bem-sucedida</li><li>Soluções para problemas comuns de instalação</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localização do código fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Entrada CLI (revisão de plano)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>Entrada CLI (revisão de código)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>Servidor de revisão de plano</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>Servidor de revisão de código</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Utilitários Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>UI de revisão de plano</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>UI de revisão de código</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>Constantes principais</strong>:</p><ul><li><code>MAX_RETRIES = 5</code>: Número de tentativas de porta (<code>packages/server/index.ts:80</code>)</li><li><code>RETRY_DELAY_MS = 500</code>: Atraso entre tentativas de porta (<code>packages/server/index.ts:80</code>)</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Inicia servidor de revisão de plano (<code>packages/server/index.ts</code>)</li><li><code>startReviewServer()</code>: Inicia servidor de revisão de código (<code>packages/server/review.ts</code>)</li><li><code>runGitDiff()</code>: Executa comando git diff (<code>packages/server/git.ts</code>)</li></ul><p><strong>Variáveis de ambiente</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE</code>: Flag de modo remoto (<code>apps/hook/server/index.ts:17</code>)</li><li><code>PLANNOTATOR_PORT</code>: Porta fixa (<code>apps/hook/server/index.ts:18</code>)</li><li><code>PLANNOTATOR_BROWSER</code>: Navegador personalizado (<code>apps/hook/README.md:79</code>)</li><li><code>PLANNOTATOR_SHARE</code>: Ativar compartilhamento por URL (<code>apps/hook/server/index.ts:44</code>)</li></ul></details>`,104)])])}const m=e(n,[["render",t]]);export{g as __pageData,m as default};
